import React, { useEffect, useState } from "react";

const Card = ({
  cardValue,
  cardSign,
  cardSignSwitchable,
  cardValueSwitchable,
}) => {
  const [value, setValue] = useState(cardValue);
  const [sign, setSign] = useState(cardSign);
  const [signSwitchable, setSignSwitchable] = useState(cardSignSwitchable);
  const [valueSwitchable, setValueSwitchable] = useState(cardValueSwitchable);

  const switchSign = () => {
    if (signSwitchable) {
      setValue(-value);
      if (sign === "positive") {
        setSign("negative");
      } else {
        setSign("positive");
      }
    }
  };

  // const switchOneTwo = () => {
  //   if (switchable) {
  //     if (value === 1) {
  //       setValue(2);
  //     } else if (value === 2) {
  //       setValue(1);
  //     }
  //   }
  // };

  const logCard = () => {
    console.log(value);
    console.log(sign);
    console.log(signSwitchable);
    console.log(valueSwitchable);
  };

  if (signSwitchable) {
    return (
      <div className="pazaakCard">
        {/* <p className="pazaakCardNumber">{value}</p> */}
        <button onClick={logCard}>{value}</button>
      </div>
    );
  } else {
    return (
      <div className="pazaakCard">
        {/* <p className="pazaakCardNumber">{value}</p> */}
        <button onClick={logCard}>{value}</button>
      </div>
    );
  }
};

export default Card;
